import javax.naming.*;
import javax.naming.directory.*;
import java.util.HashMap;
import java.util.Map;

public class LDAPUserSearch {

    private static final String LDAP_URL = "ldap://ldapserver.example.com:389/";
    private static final String LDAP_BASE_DN = "dc=example,dc=com";

    public static Map<String, String> searchUserByUsername(String username) throws NamingException {
        DirContext ctx = new InitialDirContext(new Hashtable<String, String>());
        SearchControls controls = new SearchControls();
        controls.setSearchScope(SearchControls.SUBTREE_SCOPE);
        String filter = "(uid=" + username + ")";
        NamingEnumeration<SearchResult> results = ctx.search(LDAP_BASE_DN, filter, controls);

        Map<String, String> userAttributes = new HashMap<>();
        if (results.hasMoreElements()) {
            SearchResult result = results.next();
            Attributes attrs = result.getAttributes();
            userAttributes.put("email", (String) attrs.get("mail").get());
            userAttributes.put("fullName", (String) attrs.get("displayName").get());
            userAttributes.put("department", (String) attrs.get("department").get());
        }

        ctx.close();
        return userAttributes;
    }
}